import{_ as a,o as t,c as s,a2 as n}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"DeerFlow Unique Patterns","description":"","frontmatter":{"title":"DeerFlow Unique Patterns","status":"complete"},"headers":[],"relativePath":"research/agents/deer-flow/unique-patterns.md","filePath":"research/agents/deer-flow/unique-patterns.md"}'),o={name:"research/agents/deer-flow/unique-patterns.md"};function r(i,e,l,p,c,d){return t(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="deerflow-unique-patterns" tabindex="-1">DeerFlow Unique Patterns <a class="header-anchor" href="#deerflow-unique-patterns" aria-label="Permalink to &quot;DeerFlow Unique Patterns&quot;">​</a></h1><p>DeerFlow introduces several patterns not seen in the CLI coding agents covered elsewhere in this research. These ideas are worth understanding as independent concepts, not just as DeerFlow implementation details.</p><hr><h2 id="_1-skills-as-markdown-capability-modules" tabindex="-1">1. Skills as Markdown Capability Modules <a class="header-anchor" href="#_1-skills-as-markdown-capability-modules" aria-label="Permalink to &quot;1. Skills as Markdown Capability Modules&quot;">​</a></h2><p><strong>The pattern</strong>: A &quot;skill&quot; is a <code>.md</code> file, not code.</p><p>Every other agent in this research expresses capabilities as code: TypeScript functions (Claude Code), Rust trait implementations (Codex, Goose), Python classes (OpenHands). DeerFlow&#39;s skills are <strong>declarative Markdown documents</strong> that describe a workflow, best practices, and expected outputs.</p><div class="language-markdown"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#F38BA8;"># Research Skill</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;">## Workflow</span></span>
<span class="line"><span style="color:#94E2D5;">1.</span><span style="color:#CDD6F4;"> Decompose the question into sub-questions</span></span>
<span class="line"><span style="color:#94E2D5;">2.</span><span style="color:#CDD6F4;"> Search for each sub-question</span></span>
<span class="line"><span style="color:#94E2D5;">3.</span><span style="color:#CDD6F4;"> Cross-reference sources</span></span>
<span class="line"><span style="color:#94E2D5;">4.</span><span style="color:#CDD6F4;"> Synthesize findings</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;">## Best Practices</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Verify claims with ≥ 2 sources</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Save intermediate findings to workspace/notes.md</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;">## Output Format</span></span>
<span class="line"><span style="color:#CDD6F4;">Structured report with: Summary, Findings, Sources, Confidence Assessment</span></span></code></pre></div><p><strong>Why this is interesting:</strong></p><p>The skill is consumed by the LLM directly as context — it is not parsed by code. This means:</p><ul><li>No skill registration system required; drop a <code>.md</code> file and it works</li><li>Non-engineers can author new skills without touching code</li><li>Skills can include nuanced guidance (e.g., &quot;for financial data, always cite the source date&quot;) that would be awkward to encode in function signatures</li><li>Skills are version-controlled as plain text; diffable, reviewable</li></ul><p><strong>The trade-off</strong>: Skills provide guidance but not enforcement. A code-based tool has a strict interface contract; a Markdown skill relies on the LLM to follow the workflow. This makes skills powerful for high-level orchestration guidance but less suitable for strict constraints.</p><p><strong>Closest equivalent in other agents:</strong></p><ul><li>Claude Code&#39;s <code>CLAUDE.md</code> / <code>.claude/agents/&lt;agent&gt;.md</code> — project-level Markdown instructions. But these are unstructured notes, not named installable capability modules.</li><li>Goose&#39;s <code>GOOSE_INSTRUCTIONS</code> env var — similar in being Markdown text, but not modular or on-demand loaded.</li></ul><hr><h2 id="_2-progressive-skill-loading" tabindex="-1">2. Progressive Skill Loading <a class="header-anchor" href="#_2-progressive-skill-loading" aria-label="Permalink to &quot;2. Progressive Skill Loading&quot;">​</a></h2><p><strong>The pattern</strong>: Load only the skills the current task needs; don&#39;t pre-fill the context with everything.</p><p>Most frameworks load all system context at session start. DeerFlow&#39;s task classifier infers which skills are relevant and loads only those:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>User: &quot;Create a presentation on X&quot;</span></span>
<span class="line"><span>→ Loads: slide-creation/SKILL.md</span></span>
<span class="line"><span>→ Does not load: research, report-generation, web-page, image-generation</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: &quot;Research X and then create a presentation&quot;</span></span>
<span class="line"><span>→ Loads: research/SKILL.md, slide-creation/SKILL.md</span></span>
<span class="line"><span>→ Does not load: report-generation, web-page, image-generation</span></span></code></pre></div><p><strong>Why this matters</strong>: At scale, a harness might have dozens or hundreds of skills. Loading all of them wastes context budget and confuses the model with irrelevant instructions. Progressive loading is the skills equivalent of <strong>code splitting</strong> in frontend development — you only load the module when you need it.</p><hr><h2 id="_3-super-agent-harness-vs-framework" tabindex="-1">3. Super Agent Harness vs. Framework <a class="header-anchor" href="#_3-super-agent-harness-vs-framework" aria-label="Permalink to &quot;3. Super Agent Harness vs. Framework&quot;">​</a></h2><p><strong>The concept</strong>: The distinction between a <em>framework</em> (components you wire together) and a <em>harness</em> (a complete runtime that works out of the box).</p><p>DeerFlow&#39;s documentation explicitly articulates this:</p><blockquote><p>&quot;DeerFlow 2.0 is no longer a framework you wire together. It&#39;s a super agent harness — batteries included, fully extensible.&quot;</p></blockquote><p>Traditional agent frameworks (LangChain, LangGraph, CrewAI) provide the building blocks: a graph runner, memory abstractions, tool registries. You assemble them into an agent.</p><p>A harness ships with everything pre-assembled: a filesystem, memory, skills, sandboxed execution, sub-agent spawning, IM channel dispatch, and a web UI. You run it, configure it, and extend it — but the core infrastructure is already there.</p><p><strong>The progression in this research:</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Raw LLM API</span></span>
<span class="line"><span>    └── Tool calling (function invocation)</span></span>
<span class="line"><span>        └── Agent framework (LangGraph, CrewAI — wire your own)</span></span>
<span class="line"><span>            └── Agent harness (DeerFlow — batteries included)</span></span>
<span class="line"><span>                └── Specialized agent (Claude Code — coding-first harness)</span></span></code></pre></div><p>This framing helps position DeerFlow relative to the other agents in this corpus. It&#39;s not competing with mini-SWE-agent (minimal single-purpose) or ForgeCode (specialized coding). It&#39;s competing with &quot;build your own agent infrastructure from scratch.&quot;</p><hr><h2 id="_4-ground-up-rewrite-driven-by-community-scope-creep" tabindex="-1">4. Ground-Up Rewrite Driven by Community Scope Creep <a class="header-anchor" href="#_4-ground-up-rewrite-driven-by-community-scope-creep" aria-label="Permalink to &quot;4. Ground-Up Rewrite Driven by Community Scope Creep&quot;">​</a></h2><p><strong>The pattern</strong>: v1 was a deep-research framework. The community used it as a general automation harness. ByteDance rebuilt it from scratch as a proper harness.</p><p>This is a case study in how open-source users define a tool&#39;s true purpose better than its creators:</p><ul><li>v1 was released as a deep-research automation tool</li><li>Community built data pipelines, slide decks, dashboards, content workflows on top of it</li><li>ByteDance recognized this signal: &quot;DeerFlow wasn&#39;t just a research tool. It was a harness.&quot;</li><li>v2 was a ground-up rewrite with no shared code from v1</li><li>v1 is maintained on the <code>1.x</code> branch; v2 is the active codebase</li></ul><p><strong>The implication for agent design</strong>: Minimal, composable primitives tend to be extended by users in unpredictable directions. The right response (per DeerFlow&#39;s v2 decision) is to formalize and support those extensions with proper infrastructure, rather than patching the original design.</p><hr><h2 id="_5-the-claude-code-↔-deerflow-bridge" tabindex="-1">5. The Claude Code ↔ DeerFlow Bridge <a class="header-anchor" href="#_5-the-claude-code-↔-deerflow-bridge" aria-label="Permalink to &quot;5. The Claude Code ↔ DeerFlow Bridge&quot;">​</a></h2><p><strong>The pattern</strong>: A skill that makes one agent system (Claude Code) a client of another (DeerFlow).</p><p>The <code>claude-to-deerflow</code> skill creates a bidirectional relationship between two complementary systems:</p><ul><li><strong>Claude Code</strong> excels at: coding tasks, file editing, running tests, git operations, tight feedback loops</li><li><strong>DeerFlow</strong> excels at: deep research, multi-source synthesis, parallel sub-agent fan-out, long-horizon tasks</li></ul><p>The skill lets a developer working in Claude Code delegate research-heavy or long-horizon tasks to DeerFlow without context-switching:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Claude Code session:</span></span>
<span class="line"><span>  User: /claude-to-deerflow research the landscape for [X] and write a report</span></span>
<span class="line"><span>  → Claude Code sends HTTP request to DeerFlow Gateway</span></span>
<span class="line"><span>  → DeerFlow runs ultra-mode multi-agent research</span></span>
<span class="line"><span>  → Results stream back to Claude Code session</span></span>
<span class="line"><span>  → Developer continues coding with research context available</span></span></code></pre></div><p>This is an early, practical implementation of the <strong>agent-to-agent composition</strong> pattern — one specialist agent delegating to another via protocol rather than being monolithically merged.</p><hr><h2 id="_6-im-channel-dispatch-without-public-ip" tabindex="-1">6. IM Channel Dispatch Without Public IP <a class="header-anchor" href="#_6-im-channel-dispatch-without-public-ip" aria-label="Permalink to &quot;6. IM Channel Dispatch Without Public IP&quot;">​</a></h2><p><strong>The pattern</strong>: Receive agent tasks from messaging apps without a public-facing server.</p><p>Most webhook-based integrations require a publicly accessible URL. DeerFlow&#39;s IM channel integrations use <strong>outbound-only transports</strong> that don&#39;t require ngrok, localtunnel, or cloud deployment:</p><table tabindex="0"><thead><tr><th>Channel</th><th>Transport</th><th>Direction</th></tr></thead><tbody><tr><td>Telegram</td><td>Bot API long-polling</td><td>Outbound: polls for messages</td></tr><tr><td>Slack</td><td>Socket Mode</td><td>Outbound: WebSocket to Slack servers</td></tr><tr><td>Feishu / Lark</td><td>Long Connection WebSocket</td><td>Outbound: WebSocket to Feishu servers</td></tr></tbody></table><p>This makes it possible to run DeerFlow entirely on a local machine (or behind a corporate firewall) while still receiving tasks from mobile apps and messaging platforms.</p><p><strong>Developer implication</strong>: This pattern is reusable for any agent that needs to receive tasks from messaging apps without infrastructure overhead.</p><hr><h2 id="_7-infoquest-vertically-integrated-search" tabindex="-1">7. InfoQuest: Vertically Integrated Search <a class="header-anchor" href="#_7-infoquest-vertically-integrated-search" aria-label="Permalink to &quot;7. InfoQuest: Vertically Integrated Search&quot;">​</a></h2><p><strong>The pattern</strong>: First-party search tooling integrated at the harness level.</p><p>BytePlus (ByteDance&#39;s enterprise cloud) provides <strong>InfoQuest</strong>, an intelligent search and crawling toolset. DeerFlow ships with native InfoQuest integration, giving ByteDance-ecosystem users a more structured, accurate search experience than general-purpose search APIs.</p><p>From an architectural standpoint, this represents a different model than pure MCP extensibility: the harness has an opinionated, first-party integration for a core capability (web search) rather than treating all search tools equally.</p><hr><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pattern</th><th>Why It Matters</th></tr></thead><tbody><tr><td>Skills as Markdown</td><td>Non-engineer authoring; LLM reads guidance directly; no code parsing</td></tr><tr><td>Progressive skill loading</td><td>Context budget conservation at scale; composability</td></tr><tr><td>Super agent harness concept</td><td>New category above &quot;framework&quot;; clarifies DeerFlow&#39;s positioning</td></tr><tr><td>v1→v2 rewrite</td><td>Community scope creep as product signal; importance of flexibility</td></tr><tr><td>Claude Code bridge</td><td>Agent-to-agent composition via skills; practical A2A before formal standards</td></tr><tr><td>IM channel dispatch</td><td>Outbound-only transports = no public IP required; reusable pattern</td></tr></tbody></table>`,58)])])}const g=a(o,[["render",r]]);export{u as __pageData,g as default};
